public class StudentController { private Student model; private StudentView view; public StudentController(Student m, StudentView v) { model=m; view=v; } public void setStudentName(String n) { model.setStudentName(n); } public void setGrade(String g) { model.setGrade(g); } public String getStudentName() { return model.getStudentName(); } public String getGrade() { return model.getGrade(); } public void updateView() { view.displayStudentDetails(model.getStudentId(), model.getStudentName(), model.getGrade()); } }